using Microsoft.Extensions.AI;
using OpenAI;
using ResearchAgent.Tools;

Console.WriteLine("🔬 Research Agent");
Console.WriteLine(new string('─', 50));

// --- Configuration ---
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable to run this agent.");

var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini";

// --- Tools ---
using var httpClient = new HttpClient { Timeout = TimeSpan.FromSeconds(30) };
var webSearch = new WebSearchTool(httpClient);
var noteTaking = new NoteTakingTool();

AIFunction[] tools =
[
    AIFunctionFactory.Create(webSearch.SearchWeb),
    AIFunctionFactory.Create(webSearch.FetchPage),
    AIFunctionFactory.Create(noteTaking.SaveNote),
    AIFunctionFactory.Create(noteTaking.GetNotes),
    AIFunctionFactory.Create(noteTaking.SearchNotes),
];

// --- Chat client ---
IChatClient client = new OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

// --- Get topic ---
Console.Write("\nEnter a research topic: ");
var topic = Console.ReadLine()?.Trim();

if (string.IsNullOrEmpty(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine($"\n📚 Researching: {topic}\n");

// --- Agent loop ---
const string systemPrompt = """
    You are a research agent. Your job is to research a topic thoroughly using
    the tools available to you.

    Process:
    1. Search the web with multiple varied queries to explore different angles.
    2. Fetch relevant pages when you need more detail.
    3. Save important findings as notes using the note-taking tool.
    4. After gathering enough information, retrieve all your notes.
    5. Produce a comprehensive, well-structured summary of your findings.

    Be thorough — use at least 2-3 different search queries.
    Always save key findings as notes before writing the final summary.
    """;

List<ChatMessage> messages =
[
    new(ChatRole.System, systemPrompt),
    new(ChatRole.User,
        $"Research the following topic and provide a comprehensive summary: {topic}"),
];

var chatOptions = new ChatOptions
{
    Tools = [.. tools],
};

const int maxIterations = 20;

for (int iteration = 0; iteration < maxIterations; iteration++)
{
    var response = await client.GetResponseAsync(messages, chatOptions);

    // Append response messages to conversation history
    messages.AddRange(response.Messages);

    // Collect tool calls from the response
    var calls = response.Messages
        .SelectMany(m => m.Contents.OfType<FunctionCallContent>())
        .ToList();

    if (calls.Count == 0)
    {
        // Final answer — no more tool calls
        Console.WriteLine(response.Text);
        break;
    }

    // Execute each tool call
    foreach (var call in calls)
    {
        Console.WriteLine($"  🔧 {call.Name}({FormatArgs(call.Arguments)})");

        var aiFunc = tools.FirstOrDefault(t => t.Name == call.Name);
        object? result;

        if (aiFunc is not null)
        {
            try
            {
                result = await aiFunc.InvokeAsync(call.Arguments);
            }
            catch (Exception ex)
            {
                result = $"Error: {ex.Message}";
            }
        }
        else
        {
            result = $"Unknown tool: {call.Name}";
        }

        messages.Add(new ChatMessage(ChatRole.Tool,
            [new FunctionResultContent(call.CallId, call.Name, result)]));
    }

    Console.WriteLine();

    if (iteration == maxIterations - 1)
    {
        Console.WriteLine("⚠️  Maximum iterations reached. Printing last response.");
        if (!string.IsNullOrEmpty(response.Text))
            Console.WriteLine(response.Text);
    }
}

Console.WriteLine($"\n{new string('─', 50)}");
Console.WriteLine("✅ Research complete.");

static string FormatArgs(IDictionary<string, object?>? args)
{
    if (args is null || args.Count == 0) return "";
    return string.Join(", ", args.Select(kv =>
        $"{kv.Key}: \"{Truncate(kv.Value?.ToString() ?? "", 60)}\""));
}

static string Truncate(string s, int max) =>
    s.Length <= max ? s : string.Concat(s.AsSpan(0, max - 3), "...");

