using System.ComponentModel;
using System.Net;
using System.Text.RegularExpressions;

namespace ResearchAgent.Tools;

public partial class WebSearchTool(HttpClient httpClient)
{
    [Description("Search the web for information. Returns top result snippets.")]
    public async Task<string> SearchWeb(
        [Description("The search query")] string query)
    {
        var url = $"https://html.duckduckgo.com/html/?q={WebUtility.UrlEncode(query)}";
        using var request = new HttpRequestMessage(HttpMethod.Get, url);
        request.Headers.Add("User-Agent", "ResearchAgent/1.0");

        using var response = await httpClient.SendAsync(request);
        response.EnsureSuccessStatusCode();
        var html = await response.Content.ReadAsStringAsync();

        var results = ParseSearchResults(html);
        return results.Count == 0
            ? "No results found."
            : string.Join("\n\n", results);
    }

    [Description("Fetch and extract text content from a web page URL.")]
    public async Task<string> FetchPage(
        [Description("The URL to fetch")] string url)
    {
        using var request = new HttpRequestMessage(HttpMethod.Get, url);
        request.Headers.Add("User-Agent", "ResearchAgent/1.0");

        using var response = await httpClient.SendAsync(request);
        response.EnsureSuccessStatusCode();
        var html = await response.Content.ReadAsStringAsync();

        var text = StripHtml(html);
        return text.Length > 4000 ? text[..4000] + "\n[...truncated]" : text;
    }

    private static List<string> ParseSearchResults(string html)
    {
        var results = new List<string>();
        var snippets = SnippetRegex().Matches(html);
        var titles = TitleRegex().Matches(html);

        for (int i = 0; i < Math.Min(snippets.Count, 5); i++)
        {
            var title = i < titles.Count
                ? StripHtml(titles[i].Groups[1].Value).Trim()
                : "Untitled";
            var snippet = StripHtml(snippets[i].Groups[1].Value).Trim();
            results.Add($"[{title}]\n{snippet}");
        }

        return results;
    }

    private static string StripHtml(string html)
    {
        html = ScriptStyleRegex().Replace(html, "");
        html = TagRegex().Replace(html, " ");
        html = WebUtility.HtmlDecode(html);
        html = WhitespaceRegex().Replace(html, " ");
        return html.Trim();
    }

    [GeneratedRegex(@"class=""result__snippet""[^>]*>(.*?)</", RegexOptions.Singleline)]
    private static partial Regex SnippetRegex();

